53	/// 使用用户名和密码进行 IAAA 登录
54	///
55	/// `otp_code` 为手机令牌，若账号启用了 OTP 则必须提供。
56	pub async fn login_password(
57	    client: &reqwest::Client,
58	    config: &IaaaConfig,
59	    username: &str,
60	    password: &str,
61	    otp_code: Option<&str>,
62	) -> Result<IaaaToken> {
63	    // Step 1: 获取 RSA 公钥
64	    println!("{} 获取 IAAA RSA 公钥...", "[1/3]".green());
65	    let pub_key_url = format!("{IAAA_BASE}/getPublicKey.do");
66	    let pk_resp: PublicKeyResp = client
67	        .get(&pub_key_url)
68	        .header("x-requested-with", "XMLHttpRequest")
69	        .header("referer", format!("{IAAA_BASE}/oauth.jsp"))
70	        .send()
71	        .await
72	        .context("获取公钥请求失败")?
73	        .json()
74	        .await
75	        .context("解析公钥响应失败")?;
76	
77	    if !pk_resp.success {
78	        return Err(anyhow!("获取公钥失败"));
79	    }
80	    let pem = pk_resp.key.ok_or_else(|| anyhow!("公钥为空"))?;
81	
82	    // Step 2: RSA 加密密码
83	    println!("{} 加密密码...", "[2/3]".green());
84	    let encrypted = encrypt_password(&pem, password)?;
85	
86	    // Step 3: 提交登录
87	    println!("{} 提交登录...", "[3/3]".green());
88	    let login_url = format!("{IAAA_BASE}/oauthlogin.do");
89	    let form = [
90	        ("appid", config.app_id.as_str()),
91	        ("userName", username),
92	        ("password", encrypted.as_str()),
93	        ("randCode", ""),
94	        ("smsCode", ""),
95	        ("otpCode", otp_code.unwrap_or("")),
96	        ("redirUrl", config.redirect_url.as_str()),
97	    ];
98	
99	    let resp: LoginResp = client
100	        .post(&login_url)
101	        .header("x-requested-with", "XMLHttpRequest")
102	        .header("referer", format!("{IAAA_BASE}/oauth.jsp"))
103	        .header("content-type", "application/x-www-form-urlencoded")
104	        .form(&form)
105	        .send()
106	        .await
107	        .context("登录请求失败")?
108	        .json()
109	        .await
110	        .context("解析登录响应失败")?;
111	
112	    if resp.success {
113	        let token = resp.token.ok_or_else(|| anyhow!("登录成功但 token 为空"))?;
114	        Ok(IaaaToken { token })
115	    } else {
116	        let err = resp.errors.unwrap_or(LoginError {
117	            code: None,
118	            msg: None,
119	        });
120	        Err(anyhow!(
121	            "IAAA 登录失败: code={}, msg={}",
122	            err.code.unwrap_or_default(),
123	            err.msg.unwrap_or_else(|| "未知错误".to_string())
124	        ))
125	    }
126	}
