128	/// 使用北京大学 App 扫码进行 IAAA 登录
129	pub async fn login_qrcode(
130	    client: &reqwest::Client,
131	    config: &IaaaConfig,
132	    qr_save_dir: &Path,
133	    qr_mode: crate::qr::QrDisplayMode,
134	) -> Result<IaaaToken> {
135	    // Step 0: 先访问 oauth.jsp 建立 JSESSIONID 会话
136	    println!("{} 建立 IAAA 会话...", "[1/4]".green());
137	    let oauth_url = format!(
138	        "{IAAA_BASE}/oauth.jsp?appID={}&appName=&redirectUrl={}",
139	        urlencoding(&config.app_id),
140	        urlencoding(&config.redirect_url),
141	    );
142	    let _ = client
143	        .get(&oauth_url)
144	        .send()
145	        .await
146	        .context("访问 IAAA 登录页失败")?
147	        .bytes()
148	        .await;
149	
150	    // Step 1: 获取二维码图片
151	    println!("{} 获取 IAAA 扫码二维码...", "[2/4]".green());
152	    let qr_url = format!(
153	        "{IAAA_BASE}/genQRCode.do?userName=&_rand={}&appId={}",
154	        rand::thread_rng().gen::<f64>(),
155	        urlencoding(&config.app_id),
156	    );
157	    let qr_bytes = client
158	        .get(&qr_url)
159	        .header("referer", format!("{IAAA_BASE}/oauth.jsp"))
160	        .send()
161	        .await
162	        .context("获取二维码失败")?
163	        .bytes()
164	        .await?;
165	
166	    let qr_path = qr_save_dir.join("iaaa-qrcode.png");
167	    fs::write(&qr_path, &qr_bytes)
168	        .with_context(|| format!("保存二维码失败: {}", qr_path.display()))?;
169	
170	    // Step 2: 展示二维码
171	    println!(
172	        "{} 请使用「{}」扫描下方二维码：",
173	        "[3/4]".green(),
174	        "北京大学 App".bold()
175	    );
176	    if let Err(e) = crate::qr::render_qr_image(&qr_path, qr_mode) {
177	        println!(
178	            "{} 终端无法渲染二维码（{e}），请手动打开: {}",
179	            "[warn]".yellow(),
180	            qr_path.display()
181	        );
182	    } else {
183	        println!(
184	            "    {} {}",
185	            "（二维码已保存到）".dimmed(),
186	            qr_path.display()
187	        );
188	    }
189	    println!();
190	
191	    // Step 3: 轮询等待扫码
192	    println!("{} 等待扫码确认...", "[4/4]".green());
193	    let poll_url = format!("{IAAA_BASE}/oauthlogin4QRCode.do");
194	    let form = [
195	        ("appId", "PKUApp"),
196	        ("issuerAppId", "iaaa"),
197	        ("targetAppId", config.app_id.as_str()),
198	        ("redirectUrl", config.redirect_url.as_str()),
199	    ];
200	
201	    for attempt in 0..60 {
202	        let resp: LoginResp = client
203	            .post(&poll_url)
204	            .header("x-requested-with", "XMLHttpRequest")
205	            .header("referer", format!("{IAAA_BASE}/oauth.jsp"))
206	            .form(&form)
207	            .send()
208	            .await
209	            .context("轮询请求失败")?
210	            .json()
211	            .await
212	            .context("解析轮询响应失败")?;
213	
214	        if resp.success {
215	            let token = resp.token.ok_or_else(|| anyhow!("扫码成功但 token 为空"))?;
216	            println!("   {} 扫码登录成功", "✓".green());
217	            return Ok(IaaaToken { token });
218	        }
219	
220	        // E10 = 无有效绑定 = 还未扫码，继续等
221	        let code = resp
222	            .errors
223	            .as_ref()
224	            .and_then(|e| e.code.as_deref())
225	            .unwrap_or("");
226	
227	        match code {
228	            "E10" => {
229	                if attempt == 0 {
230	                    println!("   等待扫描...");
231	                }
232	            }
233	            "E99" => {
234	                return Err(anyhow!("二维码已失效，请重试"));
235	            }
236	            _ => {
237	                let msg = resp
238	                    .errors
239	                    .as_ref()
240	                    .and_then(|e| e.msg.as_deref())
241	                    .unwrap_or("未知错误");
242	                if code == "E02" {
243	                    return Err(anyhow!("账号需要激活: {msg}"));
244	                }
245	                // 其他错误继续轮询
246	                tracing::debug!("QR poll: code={code}, msg={msg}");
247	            }
248	        }
249	
250	        let delay = 3000 + rand::thread_rng().gen_range(0..500);
251	        tokio::time::sleep(Duration::from_millis(delay)).await;
252	    }
253	
254	    Err(anyhow!("扫码超时（3分钟），请重新尝试"))
255	}
