257	/// 使用 RSA 公钥加密密码
258	fn encrypt_password(pem: &str, password: &str) -> Result<String> {
259	    let public_key = RsaPublicKey::from_public_key_pem(pem).context("解析 RSA 公钥失败")?;
260	    let mut rng = rand::thread_rng();
261	    let encrypted = public_key
262	        .encrypt(&mut rng, Pkcs1v15Encrypt, password.as_bytes())
263	        .context("RSA 加密密码失败")?;
264	    Ok(base64::engine::general_purpose::STANDARD.encode(&encrypted))
265	}
266	
267	fn urlencoding(s: &str) -> String {
268	    s.replace(' ', "%20")
269	}
