20	fn iaaa_config(device_uuid: &str) -> IaaaConfig {
21	    IaaaConfig {
22	        app_id: "PKU Helper".to_string(),
23	        redirect_url: format!(
24	            "{TREEHOLE_BASE}/chapi/cas_iaaa_login?version=3&uuid={device_uuid}&plat=web"
