29	/// 获取或生成设备 UUID
30	fn get_device_uuid(store: &Store) -> String {
31	    // 尝试从已有 session 中读取
32	    if let Ok(Some(sess)) = store.load_session() {
33	        if let Some(uuid) = sess.extra.get("device_uuid").and_then(|v| v.as_str()) {
34	            return uuid.to_string();
35	        }
36	    }
37	    // 生成新的
38	    let uuid = uuid::Uuid::new_v4();
39	    // 取最后 12 个字符，仿照 Web 端格式
40	    let hex = uuid.simple().to_string();
41	    hex[20..].to_string()
42	}
