44	fn full_device_uuid(short_uuid: &str) -> String {
45	    let full = uuid::Uuid::new_v4().to_string();
46	    format!("Web_PKUHOLE_2.0.0_WEB_UUID_{}-{}", &full[..23], short_uuid)
47	}
