49	/// 用户名密码登录
50	pub async fn login_with_password(username: Option<&str>) -> Result<()> {
51	    let store = Store::new(APP_NAME)?;
52	    check_existing_session(&store)?;
53	
54	    let cred = credential::resolve_credential(username)?;
55	
56	    let simple_client = client::build_simple()?;
57	    let device_uuid = get_device_uuid(&store);
58	    let config = iaaa_config(&device_uuid);
59	
60	    let otp_code = pkuinfo_common::otp::get_current_otp(store.config_dir())?;
61	    if otp_code.is_some() {
62	        println!("{} 已自动填入手机令牌", "[otp]".cyan());
63	    }
64	    let iaaa_token = iaaa::login_password(
65	        &simple_client,
66	        &config,
67	        &cred.username,
68	        &cred.password,
69	        otp_code.as_deref(),
70	    )
71	    .await?;
72	
73	    complete_treehole_login(&store, &iaaa_token.token, &device_uuid).await
74	}
