91	/// IAAA 认证成功后，完成树洞的登录回调
92	async fn complete_treehole_login(store: &Store, iaaa_token: &str, device_uuid: &str) -> Result<()> {
93	    println!("{} 完成树洞登录...", "[+]".green());
94	
95	    let cookie_store = store.load_cookie_store()?;
96	    let client = client::build(cookie_store.clone())?;
97	
98	    // 构造回调 URL
99	    let callback_url = format!(
100	        "{TREEHOLE_BASE}/chapi/cas_iaaa_login?version=3&uuid={device_uuid}&plat=web&_rand={}&token={iaaa_token}",
101	        rand::random::<f64>()
102	    );
103	
104	    // 发送回调请求 — 服务器会 302 重定向到 iaaa_success 页面
105	    let resp = client
106	        .get(&callback_url)
107	        .send()
108	        .await
109	        .context("树洞回调请求失败")?;
110	
111	    // 解析重定向 URL 或直接从响应中提取 token
112	    let (jwt_token, expires_in, uid) = if resp.status().is_redirection() {
113	        let location = resp
114	            .headers()
115	            .get("location")
116	            .and_then(|v| v.to_str().ok())
117	            .ok_or_else(|| anyhow!("重定向缺少 location"))?
118	            .to_string();
119	        parse_iaaa_success_url(&location)?
120	    } else {
121	        // 可能直接返回了 200，尝试从 set-cookie 中提取
122	        // 先消费 body
123	        let _ = resp.bytes().await?;
124	        // 从 cookie store 中提取
125	        extract_from_cookies(&cookie_store)?
126	    };
127	
128	    // 检查是否需要短信验证（树洞特有，首次/定期）
129	    println!("{} 检查认证状态...", "[+]".green());
130	    let full_uuid = full_device_uuid(device_uuid);
131	
132	    // 先访问 version 接口刷新 cookies
133	    let version_resp = client
134	        .get(format!(
135	            "{TREEHOLE_BASE}/chapi/version?t={}",
136	            chrono::Utc::now().timestamp_millis()
137	        ))
138	        .header("authorization", format!("Bearer {jwt_token}"))
139	        .header("uuid", &full_uuid)
140	        .send()
141	        .await;
142	    if let Ok(resp) = version_resp {
143	        let _ = resp.bytes().await;
144	    }
145	
146	    verify::check_and_verify(&client, &jwt_token, &full_uuid).await?;
147	
148	    // 保存会话
149	    let mut session = Session::new(jwt_token.clone());
150	    session.expires_at = Some(expires_in);
151	    session.uid = Some(uid.clone());
152	    session.extra = serde_json::json!({
153	        "device_uuid": device_uuid,
154	        "full_uuid": full_uuid,
155	    });
156	    store.save_session(&session)?;
157	    store.save_cookie_store(&cookie_store)?;
158	
159	    println!();
160	    println!("{} 登录成功！", "[done]".green().bold());
161	    println!("  uid       = {}", uid.bold());
162	    println!("  token     = {}...", &jwt_token[..40.min(jwt_token.len())]);
163	    println!("  expires   = {}", format_timestamp(expires_in));
164	    println!("  配置目录   = {}", store.config_dir().display());
165	    Ok(())
166	}
