168	fn parse_iaaa_success_url(url: &str) -> Result<(String, i64, String)> {
169	    let parsed = if url.starts_with("http") {
170	        url::Url::parse(url)
171	    } else {
172	        url::Url::parse(&format!("{TREEHOLE_BASE}{url}"))
173	    }
174	    .context("解析回调 URL 失败")?;
175	
176	    let mut token = None;
177	    let mut expires_in = 0i64;
178	    let mut uid = String::new();
179	
180	    for (k, v) in parsed.query_pairs() {
181	        match k.as_ref() {
182	            "token" => token = Some(v.to_string()),
183	            "expires_in" => expires_in = v.parse().unwrap_or(0),
184	            "uid" => uid = v.to_string(),
185	            _ => {}
186	        }
187	    }
188	
189	    let token = token.ok_or_else(|| anyhow!("回调 URL 中缺少 token"))?;
190	    Ok((token, expires_in, uid))
191	}
192	
193	fn extract_from_cookies(
194	    cookie_store: &std::sync::Arc<reqwest_cookie_store::CookieStoreMutex>,
195	) -> Result<(String, i64, String)> {
196	    let guard = cookie_store
197	        .lock()
198	        .map_err(|e| anyhow!("锁定 cookie store 失败: {e}"))?;
199	
200	    let mut token = None;
201	    let mut expires_in = 0i64;
202	    let mut uid = String::new();
203	
204	    for c in guard.iter_any() {
205	        match c.name() {
206	            "pku_token" => token = Some(c.value().to_string()),
207	            "pku_expires_in" => expires_in = c.value().parse().unwrap_or(0),
208	            "pku_uid" => uid = c.value().to_string(),
209	            _ => {}
210	        }
211	    }
212	
213	    let token = token.ok_or_else(|| anyhow!("cookie 中缺少 pku_token"))?;
214	    Ok((token, expires_in, uid))
215	}
