217	fn check_existing_session(store: &Store) -> Result<()> {
218	    if let Some(old) = store.load_session()? {
219	        if !old.is_expired() {
220	            println!(
221	                "{} 检测到已有登录会话 (uid={})，继续将覆盖。",
222	                "[info]".cyan(),
223	                old.uid.as_deref().unwrap_or("?")
224	            );
225	        }
226	    }
227	    Ok(())
228	}
