230	fn format_timestamp(ts: i64) -> String {
231	    chrono::DateTime::from_timestamp(ts, 0)
232	        .map(|dt| dt.format("%Y-%m-%d %H:%M:%S UTC").to_string())
233	        .unwrap_or_else(|| ts.to_string())
234	}
