236	/// 查看当前登录状态
237	pub fn status() -> Result<()> {
238	    let store = Store::new(APP_NAME)?;
239	    match store.load_session()? {
240	        Some(s) => {
241	            let expired = s.is_expired();
242	            if expired {
243	                println!("{} 会话已过期", "●".red());
244	            } else {
245	                println!("{} 已登录", "●".green());
246	            }
247	            if let Some(uid) = &s.uid {
248	                println!("  uid        = {uid}");
249	            }
250	            println!("  token      = {}...", &s.token[..40.min(s.token.len())]);
251	            if let Some(exp) = s.expires_at {
252	                println!("  expires_at = {}", format_timestamp(exp));
253	            }
254	            println!(
255	                "  created_at = {}",
256	                s.created_at.format("%Y-%m-%d %H:%M:%S UTC")
257	            );
258	            println!("  config dir = {}", store.config_dir().display());
259	        }
260	        None => {
261	            println!(
262	                "{} 未登录。运行 `treehole login` 开始扫码登录，或 `treehole login -p` 密码登录。",
263	                "○".red()
264	            );
265	        }
266	    }
267	    Ok(())
268	}
