57	impl Store {
58	    /// 创建存储实例。配置路径统一为 `~/.config/info/<sub_name>/`
59	    pub fn new(sub_name: &str) -> Result<Self> {
60	        let dirs = ProjectDirs::from("", "", "info").context("无法定位用户配置目录")?;
61	        let root = dirs.config_dir().join(sub_name);
