79	    pub fn load_session(&self) -> Result<Option<Session>> {
80	        let path = self.session_path();
81	        if !path.exists() {
82	            return Ok(None);
83	        }
84	        let bytes =
85	            fs::read(&path).with_context(|| format!("读取 session 失败: {}", path.display()))?;
86	        let sess: Session = serde_json::from_slice(&bytes)
87	            .with_context(|| format!("解析 session 失败: {}", path.display()))?;
88	        Ok(Some(sess))
89	    }
90	
91	    pub fn save_session(&self, session: &Session) -> Result<()> {
92	        let path = self.session_path();
93	        let data = serde_json::to_vec_pretty(session)?;
94	        fs::write(&path, data).with_context(|| format!("写入 session 失败: {}", path.display()))?;
95	        Ok(())
96	    }
97	
98	    pub fn load_cookie_store(&self) -> Result<Arc<CookieStoreMutex>> {
99	        let path = self.cookies_path();
100	        let store = if path.exists() {
101	            let file = fs::File::open(&path)
102	                .with_context(|| format!("打开 cookie 文件失败: {}", path.display()))?;
103	            cookie_store::serde::json::load(BufReader::new(file))
104	                .map_err(|e| anyhow::anyhow!("解析 cookie 文件失败: {e}"))?
105	        } else {
106	            CookieStore::default()
107	        };
108	        Ok(Arc::new(CookieStoreMutex::new(store)))
109	    }
110	
111	    pub fn save_cookie_store(&self, store: &Arc<CookieStoreMutex>) -> Result<()> {
112	        let path = self.cookies_path();
113	        let file = fs::File::create(&path)
114	            .with_context(|| format!("写入 cookie 文件失败: {}", path.display()))?;
115	        let guard = store
116	            .lock()
117	            .map_err(|e| anyhow::anyhow!("锁定 cookie store 失败: {e}"))?;
118	        let mut writer = BufWriter::new(file);
119	        cookie_store::serde::json::save_incl_expired_and_nonpersistent(&guard, &mut writer)
120	            .map_err(|e| anyhow::anyhow!("序列化 cookie 文件失败: {e}"))?;
121	        Ok(())
122	    }
123	
124	    pub fn clear(&self) -> Result<()> {
125	        for p in [self.session_path(), self.cookies_path()] {
126	            if p.exists() {
127	                fs::remove_file(&p).with_context(|| format!("删除 {} 失败", p.display()))?;
128	            }
129	        }
130	        Ok(())
131	    }
132	}
