1	//! 统一凭据解析模块
2	//!
3	//! 按以下优先级自动获取用户凭据：
4	//! 1. 现有 session（未过期直接复用）
5	//! 2. OS 系统密钥链（keyring）
6	//! 3. 环境变量（`PKU_USERNAME` / `PKU_PASSWORD`）
7	//! 4. 交互式输入（兜底）
8	//!
9	//! 密码 **永远不落盘** —— keyring 由操作系统加密管理，环境变量仅存在于进程内存中。
10	
11	use anyhow::{anyhow, Context, Result};
12	use colored::Colorize;
13	use std::io::{self, Write};
14	
15	use crate::session::Store;
16	
17	const ENV_USERNAME: &str = "PKU_USERNAME";
18	const ENV_PASSWORD: &str = "PKU_PASSWORD";
19	const ENV_SMS_CODE: &str = "PKU_SMS_CODE";
20	const KEYRING_SERVICE: &str = "info-pku";
21	
22	/// 凭据来源
23	#[derive(Debug, Clone, PartialEq, Eq)]
24	pub enum CredentialSource {
25	    Keyring,
26	    EnvVar,
27	    Interactive,
28	}
29	
30	/// 已解析的凭据
31	#[derive(Debug, Clone)]
32	pub struct Credential {
33	    pub username: String,
34	    pub password: String,
35	    pub source: CredentialSource,
36	}
37	
38	/// 会话检查结果
39	#[derive(Debug)]
40	pub enum SessionStatus {
41	    /// 有效且未过期
42	    Valid,
43	    /// 已过期
44	    Expired,
45	    /// 不存在
46	    NotFound,
47	}
48	
49	/// 检查指定 app 的 session 是否有效
50	pub fn check_session(app_name: &str) -> Result<SessionStatus> {
51	    let store = Store::new(app_name)?;
52	    match store.load_session()? {
53	        Some(s) => {
54	            if s.is_expired() {
55	                Ok(SessionStatus::Expired)
56	            } else {
57	                Ok(SessionStatus::Valid)
58	            }
59	        }
60	        None => Ok(SessionStatus::NotFound),
61	    }
62	}
