64	/// 解析凭据，按优先级查找：keyring → 环境变量 → 交互式输入
65	///
66	/// `username_hint` 可由调用方预填（如 elective 保存在 config.toml 中的用户名），
67	/// 仅在 keyring/env 均无凭据时作为交互式输入的默认值。
68	pub fn resolve_credential(username_hint: Option<&str>) -> Result<Credential> {
69	    // 1. 尝试 OS keyring
70	    if let Some(cred) = try_keyring()? {
71	        println!(
72	            "{} 使用系统密钥链中的凭据 ({})",
73	            "[auth]".cyan(),
74	            cred.username
75	        );
76	        return Ok(cred);
77	    }
78	
79	    // 2. 尝试环境变量
80	    if let Some(cred) = try_env_var()? {
81	        println!(
82	            "{} 使用环境变量中的凭据 ({})",
83	            "[auth]".cyan(),
84	            cred.username
85	        );
86	        return Ok(cred);
87	    }
88	
89	    // 3. 交互式输入
90	    interactive_input(username_hint)
91	}
92	
93	/// 尝试从 OS keyring 读取凭据
94	fn try_keyring() -> Result<Option<Credential>> {
95	    let kr = match keyring::Entry::new(KEYRING_SERVICE, "username") {
96	        Ok(e) => e,
97	        Err(_) => return Ok(None),
98	    };
99	
100	    let username = match kr.get_password() {
101	        Ok(u) => u,
102	        Err(keyring::Error::NoEntry) | Err(keyring::Error::PlatformFailure(_)) => return Ok(None),
103	        Err(e) => {
104	            tracing::debug!("keyring 读取用户名失败: {e}");
105	            return Ok(None);
106	        }
107	    };
108	
109	    let kr_pw = match keyring::Entry::new(KEYRING_SERVICE, "password") {
110	        Ok(e) => e,
111	        Err(_) => return Ok(None),
112	    };
113	
114	    let password = match kr_pw.get_password() {
115	        Ok(p) => p,
116	        Err(keyring::Error::NoEntry) => return Ok(None),
117	        Err(e) => {
118	            tracing::debug!("keyring 读取密码失败: {e}");
119	            return Ok(None);
120	        }
121	    };
122	
123	    Ok(Some(Credential {
124	        username,
125	        password,
126	        source: CredentialSource::Keyring,
127	    }))
128	}
129	
130	/// 尝试从环境变量读取凭据
131	fn try_env_var() -> Result<Option<Credential>> {
132	    let username = std::env::var(ENV_USERNAME).ok();
133	    let password = std::env::var(ENV_PASSWORD).ok();
134	
135	    match (username, password) {
136	        (Some(u), Some(p)) if !u.is_empty() && !p.is_empty() => Ok(Some(Credential {
137	            username: u,
138	            password: p,
139	            source: CredentialSource::EnvVar,
140	        })),
141	        _ => Ok(None),
142	    }
143	}
144	
145	/// 交互式输入凭据
146	fn interactive_input(username_hint: Option<&str>) -> Result<Credential> {
147	    let username = match username_hint {
148	        Some(hint) if !hint.is_empty() => {
149	            println!("{} 使用已保存的用户名: {}", "[info]".cyan(), hint);
150	            hint.to_string()
151	        }
152	        _ => {
153	            print!("学号/职工号: ");
154	            io::stdout().flush()?;
155	            let mut input = String::new();
156	            io::stdin().read_line(&mut input)?;
157	            input.trim().to_string()
158	        }
159	    };
160	
161	    if username.is_empty() {
162	        return Err(anyhow!("用户名不能为空"));
163	    }
164	
165	    print!("密码: ");
166	    io::stdout().flush()?;
167	    let password = rpassword::read_password().context("读取密码失败")?;
168	    if password.is_empty() {
169	        return Err(anyhow!("密码不能为空"));
170	    }
171	
172	    Ok(Credential {
173	        username,
174	        password,
175	        source: CredentialSource::Interactive,
176	    })
177	}
