179	// ─── Keyring 管理命令 ─────────────────────────────────────────
180	
181	/// 将凭据保存到 OS keyring
182	pub fn keyring_store(username: &str, password: &str) -> Result<()> {
183	    let kr_user =
184	        keyring::Entry::new(KEYRING_SERVICE, "username").context("创建 keyring entry 失败")?;
185	    kr_user
186	        .set_password(username)
187	        .context("保存用户名到 keyring 失败")?;
188	
189	    let kr_pw =
190	        keyring::Entry::new(KEYRING_SERVICE, "password").context("创建 keyring entry 失败")?;
191	    kr_pw
192	        .set_password(password)
193	        .context("保存密码到 keyring 失败")?;
194	
195	    // 立即回读验证
196	    let verify = kr_user.get_password().context("keyring 回读验证失败")?;
197	    if verify != username {
198	        return Err(anyhow!("keyring 回读验证不一致"));
199	    }
200	
201	    Ok(())
202	}
203	
204	/// 从 OS keyring 删除凭据
205	pub fn keyring_clear() -> Result<()> {
206	    for key in ["username", "password"] {
207	        if let Ok(entry) = keyring::Entry::new(KEYRING_SERVICE, key) {
208	            match entry.delete_credential() {
209	                Ok(()) => {}
210	                Err(keyring::Error::NoEntry) => {}
211	                Err(e) => {
212	                    return Err(anyhow!("删除 keyring 中的 {key} 失败: {e}"));
213	                }
214	            }
215	        }
216	    }
217	    Ok(())
218	}
219	
220	/// 检查 keyring 中是否存储了凭据，返回 (是否存在, 错误详情)
221	pub fn keyring_has_credential() -> (bool, Option<String>) {
222	    let entry = match keyring::Entry::new(KEYRING_SERVICE, "username") {
223	        Ok(e) => e,
224	        Err(e) => return (false, Some(format!("创建 entry 失败: {e}"))),
225	    };
226	    match entry.get_password() {
227	        Ok(_) => (true, None),
228	        Err(keyring::Error::NoEntry) => (false, None),
229	        Err(e) => (false, Some(format!("读取失败: {e}"))),
230	    }
231	}
