233	// ─── 短信验证码解析 ──────────────────────────────────────────
234	
235	/// 获取短信验证码：环境变量 `PKU_SMS_CODE` → 交互式输入
236	///
237	/// AI Agent 可以先询问用户获取验证码，再通过环境变量传入，
238	/// 避免 Agent 需要控制 stdin。
239	pub fn resolve_sms_code(prompt: &str) -> Result<String> {
240	    // 1. 检查环境变量
241	    if let Ok(code) = std::env::var(ENV_SMS_CODE) {
242	        let code = code.trim().to_string();
243	        if !code.is_empty() {
244	            println!("{} 使用环境变量中的短信验证码", "[auth]".cyan());
245	            return Ok(code);
246	        }
247	    }
248	
249	    // 2. 交互式输入
250	    print!("{prompt}");
251	    io::stdout().flush()?;
252	    let mut code = String::new();
253	    io::stdin().read_line(&mut code)?;
254	    let code = code.trim().to_string();
255	    if code.is_empty() {
256	        return Err(anyhow!("验证码不能为空"));
257	    }
258	    Ok(code)
259	}
260	
261	/// 获取是/否确认：环境变量 `PKU_SMS_CODE` 存在时自动确认，否则交互式询问
262	///
263	/// 当 Agent 通过环境变量传入验证码时，自动跳过"是否发送"的确认步骤。
264	pub fn confirm_send_sms(prompt: &str) -> Result<bool> {
265	    // 如果环境变量中已有验证码，自动确认发送
266	    if std::env::var(ENV_SMS_CODE).is_ok() {
267	        println!("{} 自动确认发送短信验证码", "[auth]".cyan());
268	        return Ok(true);
269	    }
270	
271	    print!("{prompt}");
272	    io::stdout().flush()?;
273	    let mut input = String::new();
274	    io::stdin().read_line(&mut input)?;
275	    Ok(!input.trim().eq_ignore_ascii_case("n"))
276	}
